export function graphql(source: "query SourceWidget {\n  user {\n    id\n    dataSources {\n      id\n      name\n      paused\n      createdAt\n      updatedAt\n      lastSyncedAt\n      lastSuccessfulAt\n      lastSuccessfulRuntime\n      lastResult\n      lastFailedAt\n      lastFailedRuntime\n      lastAttemptedAt\n      lastError\n      source\n      config\n    }\n  }\n}"): (typeof documents)["query SourceWidget {\n  user {\n    id\n    dataSources {\n      id\n      name\n      paused\n      createdAt\n      updatedAt\n      lastSyncedAt\n      lastSuccessfulAt\n      lastSuccessfulRuntime\n      lastResult\n      lastFailedAt\n      lastFailedRuntime\n      lastAttemptedAt\n      lastError\n      source\n      config\n    }\n  }\n}"];

export function graphql(source: string) {
  return (documents as any)[source] ?? {};
}

export type DocumentType<TDocumentNode extends DocumentNode<any, any>> = TDocumentNode extends DocumentNode<  infer TType,  any>  ? TType  : never;